SELECT first_name || ' ' || last_name AS full_name, CEIL(number_of_dependents) AS dependent_count
FROM loan_applicants
ORDER BY dependent_count DESC;

SELECT applicant_id, MIN(credit_score) AS minimum_credit_score
FROM credit_reports
GROUP BY applicant_id;

SELECT disbursement_id, disbursement_amount, disbursement_date
FROM loan_disbursements
ORDER BY disbursement_date DESC;

SELECT first_name, last_name
FROM loan_applicants
ORDER BY last_name ASC;

SELECT first_name, last_name, number_of_dependents
FROM loan_applicants
ORDER BY number_of_dependents DESC;
